using Random = UnityEngine.Random;

public class Gun : MonoBehaviour {
    public enum ShootState {
        Ready,
        Shooting,
        Reloading
    }

    // The Gun
    XRGrabInteractable m_InteractableBase;

    //Gun Colliders
    //public Collider Gun_Collider_Physical = null;

